const items = $input.all();
const filterIds = ($env.MOODLE_COURSE_IDS || '').split(',').map(s => s.trim()).filter(Boolean);

const courses = items.filter(item => {
  // Skip site-level course (id=1)
  if (item.json.id === 1) return false;
  // If filter list provided, only keep matching IDs
  if (filterIds.length > 0) {
    return filterIds.includes(String(item.json.id));
  }
  return true;
});

return courses.map(item => ({ json: item.json }));

const SUPPORTED_MIMES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  'text/markdown'
];

// Get course info from the Loop Courses node
const courseItem = $('Loop Courses').item;
const courseId = courseItem.json.id;
const rawShortname = courseItem.json.shortname || `course-${courseId}`;
const namespace = rawShortname.toLowerCase().replace(/\s+/g, '-');

const response = $input.first();
const sections = response.json.body || response.json;

const files = [];

if (!Array.isArray(sections)) {
  // API returned an error or unexpected format
  return [{ json: { error: 'Unexpected response format', courseId, namespace, files: [] } }];
}

for (const section of sections) {
  if (!section.modules) continue;
  for (const mod of section.modules) {
    if (!mod.contents) continue;
    for (const content of mod.contents) {
      if (content.type !== 'file') continue;
      if (!SUPPORTED_MIMES.includes(content.mimetype)) continue;

      // Prefix filename with module ID to avoid collisions across sections
      const uniqueFilename = `mod${mod.id}_${content.filename}`;

      files.push({
        fileurl: content.fileurl,
        filename: content.filename,
        uniqueFilename: uniqueFilename,
        filesize: content.filesize,
        timemodified: content.timemodified,
        mimetype: content.mimetype,
        moduleId: mod.id,
        moduleName: mod.name,
        sectionName: section.name,
        courseId: courseId,
        namespace: namespace
      });
    }
  }
}

return [{ json: { courseId, namespace, files } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.courseFiles) {
  staticData.courseFiles = {};
}

const input = $input.first().json;
const namespace = input.namespace;
const courseId = input.courseId;
const currentFiles = input.files || [];

const storedFiles = staticData.courseFiles[namespace] || {};

const toIngest = [];    // new or updated files
const toDelete = [];    // removed files
const unchanged = [];   // no change

// Build set of current file URLs for removal detection
const currentFileUrls = new Set(currentFiles.map(f => f.fileurl));

// Check each current file against stored state
for (const file of currentFiles) {
  const stored = storedFiles[file.fileurl];
  if (!stored) {
    // New file
    toIngest.push({ ...file, action: 'new' });
  } else if (stored.timemodified !== file.timemodified) {
    // Updated file
    toIngest.push({ ...file, action: 'updated', old_document_id: stored.document_id });
  } else {
    unchanged.push({ ...file, action: 'unchanged' });
  }
}

// Check for removed files (in state but not in current contents)
for (const [fileurl, stored] of Object.entries(storedFiles)) {
  if (!currentFileUrls.has(fileurl)) {
    toDelete.push({
      fileurl,
      filename: stored.filename,
      document_id: stored.document_id,
      namespace,
      action: 'removed'
    });
  }
}

return [{
  json: {
    courseId,
    namespace,
    toIngest,
    toDelete,
    unchanged,
    summary: {
      new: toIngest.filter(f => f.action === 'new').length,
      updated: toIngest.filter(f => f.action === 'updated').length,
      removed: toDelete.length,
      unchanged: unchanged.length
    }
  }
}];

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const namespace = input.namespace;
const toDelete = input.toDelete || [];

const results = [];

for (const file of toDelete) {
  if (file.document_id) {
    results.push({
      json: {
        document_id: file.document_id,
        namespace: file.namespace || namespace,
        filename: file.filename,
        fileurl: file.fileurl
      }
    });
  }

  // Remove from state
  if (staticData.courseFiles && staticData.courseFiles[namespace]) {
    delete staticData.courseFiles[namespace][file.fileurl];
  }
}

if (results.length === 0) {
  return [{ json: { message: 'No documents to delete', namespace } }];
}

return results;

const input = $('Dedup & Diff').item.json;
const toIngest = input.toIngest || [];

return toIngest.map(file => ({ json: file }));

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const namespace = input.namespace;

// If this is an updated file, delete old document first
if (input.action === 'updated' && input.old_document_id) {
  return [{
    json: {
      ...input,
      delete_first: true,
      old_document_id: input.old_document_id,
      namespace: namespace
    }
  }];
}

return [{ json: { ...input, delete_first: false } }];

// Carry forward metadata from previous nodes so it's available for POST /ingest
const item = $input.first();
const prevData = $('Check Update Delete').item.json;

// Rename binary key to 'data' for the multipart upload
const binary = item.binary || {};
const binaryKey = Object.keys(binary)[0];

const newBinary = {};
if (binaryKey) {
  newBinary.data = {
    ...binary[binaryKey],
    fileName: prevData.uniqueFilename || prevData.filename
  };
}

return [{
  json: {
    fileurl: prevData.fileurl,
    filename: prevData.filename,
    uniqueFilename: prevData.uniqueFilename,
    namespace: prevData.namespace,
    courseId: prevData.courseId,
    timemodified: prevData.timemodified,
    action: prevData.action
  },
  binary: newBinary
}];

const MAX_POLLS = 60;
const staticData = $getWorkflowStaticData('node');
staticData.pollCount = (staticData.pollCount || 0) + 1;

const items = $input.all();

if (staticData.pollCount > MAX_POLLS) {
  staticData.pollCount = 0;
  return items.map(item => ({
    json: {
      ...item.json,
      status: 'timeout',
      error_message: `Poll timeout after ${MAX_POLLS * 5}s`
    }
  }));
}

if (items[0]?.json?.status !== 'processing') {
  staticData.pollCount = 0;
}

return items;

const item = $input.first();
const ingestResponse = $('POST /ingest').item.json;
const fileData = $('Prepare Upload').item.json;
const staticData = $getWorkflowStaticData('global');

const statusCode = ingestResponse.statusCode || 200;
const body = ingestResponse.body || ingestResponse;

const documentId = item.json.document_id || body.document_id || null;
const rawStatus = item.json.status || body.status || (statusCode >= 200 && statusCode < 300 ? 'completed' : 'failed');
// Vektra returns 'new' for first ingest, 'exists' for dedup hit — normalize to 'completed'
const status = ((rawStatus === 'new' || rawStatus === 'exists') && documentId) ? 'completed' : rawStatus;
const chunkCount = item.json.chunk_count || body.chunk_count || 0;
const error = item.json.error_message || body.error?.message || body.detail?.error?.message || null;

// Update state with successful ingestion
if (documentId && status === 'completed') {
  const namespace = fileData.namespace;
  if (!staticData.courseFiles[namespace]) {
    staticData.courseFiles[namespace] = {};
  }
  staticData.courseFiles[namespace][fileData.fileurl] = {
    timemodified: fileData.timemodified,
    document_id: documentId,
    filename: fileData.uniqueFilename || fileData.filename,
    last_synced: new Date().toISOString()
  };
}

return [{
  json: {
    document_id: documentId,
    chunk_count: chunkCount,
    status,
    file_name: fileData.uniqueFilename || fileData.filename,
    namespace: fileData.namespace,
    courseId: fileData.courseId,
    action: fileData.action,
    error
  }
}];

// Merge results from the Loop Courses node
// This collects all no-op and completed items
const items = $input.all();

let totalNew = 0;
let totalUpdated = 0;
let totalRemoved = 0;
let totalUnchanged = 0;
let totalFailed = 0;
const details = [];

for (const item of items) {
  const d = item.json;
  if (d.action === 'new' && (d.status === 'completed' || d.status === 'new')) totalNew++;
  else if (d.action === 'updated' && (d.status === 'completed' || d.status === 'new')) totalUpdated++;
  else if (d.action === 'removed') totalRemoved++;
  else if (d.action === 'unchanged') totalUnchanged++;
  else if (d.status === 'failed' || d.status === 'timeout') totalFailed++;

  if (d.file_name || d.filename) {
    details.push({
      file: d.file_name || d.filename,
      namespace: d.namespace,
      action: d.action || 'unknown',
      status: d.status || 'n/a',
      document_id: d.document_id || null,
      error: d.error || null
    });
  }
}

const summary = `Sync complete: ${totalNew} new, ${totalUpdated} updated, ${totalRemoved} removed, ${totalUnchanged} unchanged, ${totalFailed} failed`;

console.log(summary);

return [{
  json: {
    summary,
    totals: { new: totalNew, updated: totalUpdated, removed: totalRemoved, unchanged: totalUnchanged, failed: totalFailed },
    details
  }
}];

// Pass-through for no-op courses (no ingestions and no deletions)
const input = $('Dedup & Diff').item.json;
const unchangedItems = (input.unchanged || []).map(f => ({
  json: {
    file_name: f.uniqueFilename || f.filename,
    namespace: input.namespace,
    courseId: input.courseId,
    action: 'unchanged',
    status: 'skipped'
  }
}));

if (unchangedItems.length === 0) {
  return [{ json: { namespace: input.namespace, courseId: input.courseId, action: 'no_files', status: 'skipped' } }];
}

return unchangedItems;
